// For languages not fully translated, fall back to English
const FALLBACK = 'en';

export function useTranslations(langCode) {
  const code = langCode?.replace('-', '_').toLowerCase();
  const translations = T[code] || T[FALLBACK];
  return translations;
}

// Map Telegram language codes to our codes
export function mapTelegramLang(telegramLangCode) {
  const map = {
    'en': 'en', 'fr': 'fr', 'pl': 'pl', 'zh': 'zh_cn',
    'vi': 'vi', 'ar': 'ar', 'ru': 'ru', 'es': 'es',
    'pt': 'pt', 'it': 'it', 'id': 'id', 'uk': 'uk',
    'cs': 'cs', 'bg': 'bg', 'lv': 'lv', 'sv': 'sv',
    'sk': 'sk', 'da': 'da', 'et': 'et', 'ro': 'ro',
    'hu': 'hu', 'de': 'de', 'lt': 'lt',
  };
  return map[telegramLangCode] || 'en';
}
